constexpr size_t kDefaultWorkgroupSize = 256;
constexpr unsigned int kDefaultElementsPerWi = 8;
constexpr unsigned int kDefaultFusionDegree = 4;
constexpr bool kDefaultBlockStrided = false;
constexpr size_t kHalf2SizeBytes = 4;

struct Half2 {
  uint16_t x;
  uint16_t y;
};

static inline uint16_t float_to_half(float f) {
  uint32_t x;
  std::memcpy(&x, &f, sizeof(x));
  uint32_t sign = (x >> 16) & 0x8000u;
  uint32_t mantissa = x & 0x007fffffu;
  int exp = static_cast<int>((x >> 23) & 0xffu) - 127 + 15;

  if (exp <= 0) {
    if (exp < -10) return static_cast<uint16_t>(sign);
    mantissa = (mantissa | 0x00800000u) >> (1 - exp);
    if (mantissa & 0x00001000u) mantissa += 0x00002000u;
    return static_cast<uint16_t>(sign | (mantissa >> 13));
  } else if (exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7c00u);
  } else {
    if (mantissa & 0x00001000u) {
      mantissa += 0x00002000u;
      if (mantissa & 0x00800000u) {
        mantissa = 0;
        exp += 1;
        if (exp >= 31) return static_cast<uint16_t>(sign | 0x7c00u);
      }
    }
    return static_cast<uint16_t>(sign | (static_cast<uint32_t>(exp) << 10) |
                                 (mantissa >> 13));
  }
}

static inline float half_to_float(uint16_t h) {
  uint32_t sign = (static_cast<uint32_t>(h & 0x8000u)) << 16;
  uint32_t exp = (h >> 10) & 0x1fu;
  uint32_t mant = h & 0x03ffu;
  uint32_t out;

  if (exp == 0) {
    if (mant == 0) {
      out = sign;
    } else {
      exp = 1;
      while ((mant & 0x0400u) == 0) {
        mant <<= 1;
        exp--;
      }
      mant &= 0x03ffu;
      exp = exp + (127 - 15);
      out = sign | (exp << 23) | (mant << 13);
    }
  } else if (exp == 31) {
    out = sign | 0x7f800000u | (mant << 13);
  } else {
    exp = exp + (127 - 15);
    out = sign | (exp << 23) | (mant << 13);
  }

  float f;
  std::memcpy(&f, &out, sizeof(f));
  return f;
}

static inline Half2 h2_from_float(float v) {
  const uint16_t h = float_to_half(v);
  return Half2{h, h};
}
static inline Half2 h2_add(Half2 a, Half2 b) {
  return Half2{float_to_half(half_to_float(a.x) + half_to_float(b.x)),
               float_to_half(half_to_float(a.y) + half_to_float(b.y))};
}
static inline Half2 h2_mul(Half2 a, Half2 b) {
  return Half2{float_to_half(half_to_float(a.x) * half_to_float(b.x)),
               float_to_half(half_to_float(a.y) * half_to_float(b.y))};
}
static inline bool h2_equal(Half2 a, Half2 b) { return a.x == b.x && a.y == b.y; }

template <typename F>
double benchmark(F&& fn, int iters = 3) {
  double sum = 0.0;
  for (int i = 0; i < iters; ++i) sum += fn();
  return sum / static_cast<double>(iters);
}

template <typename T>
void kernel_run_scalar(T seed,
                       T* g_data,
                       long size,
                       int current_compute_iterations,
                       size_t workgroupsize,
                       unsigned int elements_per_wi,
                       unsigned int fusion_degree,
                       bool block_strided) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const long num_groups =
      (compute_grid_size + static_cast<long>(workgroupsize) - 1) /
      static_cast<long>(workgroupsize);
  const long big_stride =
      num_groups * static_cast<long>(workgroupsize) * elements_per_wi;

#pragma omp parallel
  {
    std::vector<T> tmps(elements_per_wi);
#pragma omp for schedule(static)
    for (long gid = 0; gid < compute_grid_size; ++gid) {
      long idx, stride;
      if (block_strided) {
        const long group_id = gid / static_cast<long>(workgroupsize);
        const long local_id = gid % static_cast<long>(workgroupsize);
        stride = static_cast<long>(workgroupsize);
        idx = group_id * static_cast<long>(workgroupsize) * elements_per_wi +
              local_id;
      } else {
        stride = compute_grid_size;
        idx = gid;
      }

      for (unsigned int k = 0; k < fusion_degree; ++k) {
        for (unsigned int j = 0; j < elements_per_wi; ++j) {
          const long off = idx + static_cast<long>(j) * stride +
                           static_cast<long>(k) * big_stride;
          T v = g_data[off];
          for (int i = 0; i < current_compute_iterations; ++i) v = v * v + seed;
          tmps[j] = v;
        }

        T sum = static_cast<T>(0);
        for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2)
          sum += tmps[j] * tmps[j + 1];

        if (sum == static_cast<T>(-1))
          g_data[idx + static_cast<long>(k) * big_stride] = sum;
      }
    }
  }
}

void kernel_run_half(Half2 seed,
                     Half2* g_data,
                     long size,
                     int current_compute_iterations,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool block_strided) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const long num_groups =
      (compute_grid_size + static_cast<long>(workgroupsize) - 1) /
      static_cast<long>(workgroupsize);
  const long big_stride =
      num_groups * static_cast<long>(workgroupsize) * elements_per_wi;
  const Half2 minus_one = h2_from_float(-1.0f);

#pragma omp parallel
  {
    std::vector<Half2> tmps(elements_per_wi);
#pragma omp for schedule(static)
    for (long gid = 0; gid < compute_grid_size; ++gid) {
      long idx, stride;
      if (block_strided) {
        const long group_id = gid / static_cast<long>(workgroupsize);
        const long local_id = gid % static_cast<long>(workgroupsize);
        stride = static_cast<long>(workgroupsize);
        idx = group_id * static_cast<long>(workgroupsize) * elements_per_wi +
              local_id;
      } else {
        stride = compute_grid_size;
        idx = gid;
      }

      for (unsigned int k = 0; k < fusion_degree; ++k) {
        for (unsigned int j = 0; j < elements_per_wi; ++j) {
          const long off = idx + static_cast<long>(j) * stride +
                           static_cast<long>(k) * big_stride;
          Half2 v = g_data[off];
          for (int i = 0; i < current_compute_iterations; ++i) {
            v = h2_add(h2_mul(v, v), seed);
          }
          tmps[j] = v;
        }

        Half2 sum = h2_from_float(0.0f);
        for (unsigned int j = 0; j + 1 < elements_per_wi; j += 2)
          sum = h2_add(sum, h2_mul(tmps[j], tmps[j + 1]));

        if (h2_equal(sum, minus_one))
          g_data[idx + static_cast<long>(k) * big_stride] = sum;
      }
    }
  }
}

void runbench(const int compute_iterations[],
              unsigned int krn_idx,
              void* cbuffer,
              long size,
              size_t workgroupsize,
              unsigned int elements_per_wi,
              unsigned int fusion_degree,
              bool block_strided) {
  const long compute_grid_size = size / elements_per_wi / fusion_degree;
  const int current_compute_iterations = compute_iterations[krn_idx];
  const long long computations =
      (elements_per_wi * (long long)compute_grid_size +
       (2 * elements_per_wi * current_compute_iterations) *
           (long long)compute_grid_size) *
      fusion_degree;
  const long long memoryoperations = size;

  auto time_ms = [](auto&& fn) {
    auto ts_start = std::chrono::high_resolution_clock::now();
    fn();
    auto ts_end = std::chrono::high_resolution_clock::now();
    return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
  };

  double kernel_time_mad_sp = benchmark([&]() {
    const float seed_f = 1.0f;
    kernel_run_scalar<float>(seed_f, reinterpret_cast<float*>(cbuffer), size,
                             current_compute_iterations, workgroupsize,
                             elements_per_wi, fusion_degree, block_strided);
    return time_ms([]() {});
  });

  kernel_time_mad_sp = benchmark([&]() {
    const float seed_f = 1.0f;
    return time_ms([&]() {
      kernel_run_scalar<float>(seed_f, reinterpret_cast<float*>(cbuffer), size,
                               current_compute_iterations, workgroupsize,
                               elements_per_wi, fusion_degree, block_strided);
    });
  });

  double kernel_time_mad_dp = benchmark([&]() {
    const double seed_d = 1.0;
    return time_ms([&]() {
      kernel_run_scalar<double>(seed_d, reinterpret_cast<double*>(cbuffer), size,
                                current_compute_iterations, workgroupsize,
                                elements_per_wi, fusion_degree, block_strided);
    });
  });

  double kernel_time_mad_hp = benchmark([&]() {
    const Half2 seed_h = h2_from_float(1.0f);
    return time_ms([&]() {
      kernel_run_half(seed_h, reinterpret_cast<Half2*>(cbuffer), size,
                      current_compute_iterations, workgroupsize, elements_per_wi,
                      fusion_degree, block_strided);
    });
  });

  double kernel_time_mad_int = benchmark([&]() {
    const int seed_i = 1;
    return time_ms([&]() {
      kernel_run_scalar<int>(seed_i, reinterpret_cast<int*>(cbuffer), size,
                             current_compute_iterations, workgroupsize,
                             elements_per_wi, fusion_degree, block_strided);
    });
  });

  std::printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      current_compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * kHalf2SizeBytes),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * kHalf2SizeBytes) / kernel_time_mad_hp *
          1000. / (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

