void mixbenchCPU(void* c, size_t bytes) {
  const long size = static_cast<long>(bytes / sizeof(double));

  std::printf("Workitem stride:        %s\n",
              kDefaultBlockStrided ? "Workgroup" : "NDRange");
  std::printf("Buffer allocation:      Device allocated\n");
  std::printf("Timer:                  OS based\n");

  int* mapped_data = reinterpret_cast<int*>(c);
  for (long i = 0; i < size; i++) mapped_data[i] = 0;

  kernel_run_scalar<short>(1, reinterpret_cast<short*>(c), size, 0,
                           kDefaultWorkgroupSize, 1, 1, kDefaultBlockStrided);

  std::printf(
      "-----------------------------------------------------------------------------"
      " CSV data "
      "-----------------------------------------------------------------------------"
      "\n");
  std::printf(
      "Experiment ID, Single Precision ops,,,,              Double precision "
      "ops,,,,              Half precision ops,,,,                Integer "
      "operations,,, \n");
  std::printf(
      "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
      "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
      "Iops/byte, ex.time,   GIOPS, GB/sec\n");

  for (int i = 0; i < compute_iterations_len; i++) {
    runbench(compute_iterations, i, c, size, kDefaultWorkgroupSize,
             kDefaultElementsPerWi, kDefaultFusionDegree, kDefaultBlockStrided);
  }

  std::printf(
      "-----------------------------------------------------------------------------"
      "-----------------------------------------------------------------------------"
      "--------------------\n");
}
